```javascript
// Merge linked list function
const mergeLinkedLists = (head1, head2) => {
  // Initialize temporary variables
  let temp1 = head1;
  let temp2 = head2;

  // Create a new linked list 
  let mergedList = null;
  let tail = null;

  // Traverse through both lists 
  while (temp1 !== null && temp2 !== null) {
    // Add the smaller node to the end of the new list
    if (temp1.data < temp2.data) {
      if (mergedList === null) {
        mergedList = temp1;
        tail = mergedList;
      } else {
        tail.next = temp1;
        tail = tail.next;
      }
      temp1 = temp1.next;
    } else {
      if (mergedList === null) {
        mergedList = temp2;
        tail = mergedList;
      } else {
        tail.next = temp2;
        tail = tail.next;
      }
      temp2 = temp2.next;
    }
  }

  // If there is still any element left in either list
  if (temp1 !== null) {
    tail.next = temp1;
  }

  if (temp2 !== null) {
    tail.next = temp2;
  }

  // Return the head of the merged linked list
  return mergedList;
};
