def longestSubString(string):
    for char in string:
        longest = ''
        longest_length = 0;
        start_index = 0;
        temp = '';
        temp_length = 0;
        for i in range(start_index, len(string)):
            if char == string[i]:
                temp += char
                temp_length += 1
                if temp_length > longest_length:
                    longest_length = temp_length
                    longest = temp
            else:
                start_index += 1
        return longest
