    } else if (this.sign_with) {
      ret = this.sign_with.get_keypair()
    } else if (this.sender_keypair) {
      ret = this.sender_keypair
    } else if (encrypt) {
      await dh.Pair.generate({}, (err, sender_keypair) => {
        this.sender_keypair = sender_keypair
        ret = sender_keypair
        this.ephemeral = true
      })
    } else if (this.sender_key) {
      [err, this.sender_keypair] = dh.Pair.parse_kb(this.sender_key)
      if (!err) {
        ret = this.sender_keypair
      }
    } else {
      err = new Error("Cannot encrypt without a sender keypair")
    }
    cb(err, ret)
  }

  async encrypt(params, cb) {
    const esc = make_esc(cb, "encrypt")
    await this.get_sender_keypair({ encrypt: true }, esc, (err, sender) => {
      const recvr = this.encrypt_for.get_keypair()
      recvr.encrypt_kb({ plaintext: this.plaintext, sender }, esc, ({ ciphertext, nonce }) => {
        this.ciphertext = ciphertext
        this.nonce = nonce
        this.sender_key = sender.ekid()
        this.receiver_key = recvr.ekid()
        cb(null)
      })
    })
  }

  async decrypt({ sign_with, encrypt_for }, cb) {
    const esc = make_esc(cb, "decrypt")
    await this.get_sender_keypair({ sign_with }, esc, (err, sender) => {
      const args = { ciphertext: this.ciphertext, nonce: this.nonce, sender }
      const recvr = encrypt_for.get_keypair()
      recvr.decrypt_kb(args, esc, (plaintext) => {
        cb(null, { sender_keypair: sender, plaintext, receiver_keypair: recvr })
      })
    })
  }

  async unbox({ encrypt_for }, cb) {
    await this.decrypt({ encrypt_for }, (err, res) => {
      cb(err, res)
    })
  }

  static box({ sign_with, encrypt_for, plaintext, anonymous }, cb) {
    const packet = new Encryption({ sign_with, encrypt_for, plaintext, anonymous })
    await packet.encrypt({}, (err) => {
      if (!err) {
        cb(err, packet)
      }
      packet = null
    })
  }
}

