namespace cu {
    // Define the CUDA kernel for resizing with padding
    template<typename T, int numChannel, bool isPlanar>
    __global__ void gpuRGBLikeResizePadding(const T* __restrict__ input, int iWidth, int iHeight, int pitch, float2 scale, T* __restrict__ output, int oWidth, int oHeight, int padd_w, int padd_h)
    {
        const int x = blockIdx.x * blockDim.x + threadIdx.x;
        const int y = blockIdx.y * blockDim.y + threadIdx.y;

        if (x >= oWidth || y >= oHeight)
            return;

        const int dx = ((float)x * scale.x);
        const int dy = ((float)y * scale.y);

        if (isPlanar) 
        {
#pragma unroll
            for (int k = 0; k < numChannel; ++k)
            {
                // Perform sampling on the original image and apply padding
                if((dx < iWidth) && (dy < iHeight))
                {
                    output[oWidth * oHeight * k + (y+padd_h) * oWidth + (x+padd_w)] = input[dx * dy * k + dy * iWidth + dx];
                }
                // Fill the padded area with 0
                if(x < padd_w || y < padd_h || x >= (oWidth-padd_w) ||  y >= (oHeight - padd_h))
                {
                     output[oWidth * oHeight * k + y * oWidth + x] = 0;
                }    
            }
        }
        else 
        {
#pragma unroll
            for (int k = 0; k < numChannel; ++k)
            {
                // Perform sampling on the original image and apply padding
                if((dx < iWidth) && (dy < iHeight))
                {
                    output[(y+padd_h) * oWidth * numChannel + (x+padd_w) * numChannel + k] = input[dy * pitch + dx * numChannel + k];
                }
                // Fill the padded area with 0
                if(x < padd_w || y < padd_h || x >= (oWidth-padd_w) ||  y >= (oHeight - padd_h))
                {
                     output[y * oWidth * numChannel + x * numChannel + k] = 0;
                }
            }
        }
    }

    // Define the CUDA function for resizing with padding
    template<typename T>
    cudaError_t cudaResizePaddingRGBLike(T* input, size_t inputWidth, size_t inputHeight, int pitch, ImageFormat inputImageFormat, T* output, size_t outputWidth, size_t outputHeight, cudaStream_t stream) {
        if (!input || !output)
            return cudaErrorInvalidDevicePointer;

        if (inputWidth == 0 || outputWidth == 0 || inputHeight == 0 || outputHeight == 0 || pitch == 0)
            return cudaErrorInvalidValue;

        // Calculate the scale for resizing
        float r = max(float(inputWidth) / float(outputWidth), float(inputHeight) / float(outputHeight));
        float2 scale = make_float2(r, r);
        int inside_w = round(inputWidth/r);
        int inside_h = round(inputHeight/r);
        float padd_w = outputWidth -  inside_w ;
        float padd_h = outputHeight - inside_h ;
        padd_w = padd_w/2;
        padd_h = padd_h/2;

        // Launch the CUDA kernel for resizing with padding
        const dim3 blockDim(32, 32);
        const dim3 gridDim(iDivUp(outputWidth, blockDim.x), iDivUp(outputHeight, blockDim.y));

        switch (inputImageFormat) {
        case ImageFormat::IMAGE_RGB8:
        case ImageFormat::IMAGE_BGR8:
            gpuRGBLikeResizePadding<T, 3, false> << <gridDim, blockDim, 0, stream >> >(input, inputWidth, inputHeight, pitch, scale, output, outputWidth, outputHeight,  padd_w,  padd_h);
            break;
        case ImageFormat::IMAGE_RGBA8:
        case ImageFormat::IMAGE_BGRA8:
            gpuRGBLikeResizePadding<T, 4, false> << <gridDim, blockDim, 0, stream >> >(input, inputWidth, inputHeight, pitch, scale, output, outputWidth, outputHeight,  padd_w,  padd_h);
            break;
        case ImageFormat::IMAGE_GRAY8:
            gpuRGBLikeResizePadding<T, 1, false> << <gridDim, blockDim, 0, stream >> >(input, inputWidth, inputHeight, pitch, scale, output, outputWidth, outputHeight,  padd_w,  padd_h);
            break;
        case ImageFormat::IMAGE_RGB32F_PLANAR:
            gpuRGBLikeResizePadding<T, 3, true> << <gridDim, blockDim, 0, stream >> >(input, inputWidth, inputHeight, pitch, scale, output, outputWidth, outputHeight,  padd_w,  padd_h);
            break;
        default:
            return cudaErrorInvalidValue;
        }

        return CUDA(cudaGetLastError());
    }

    // Instantiate the template for unsigned char and float types
    template cudaError_t cudaResizePaddingRGBLike(unsigned char* input, size_t inputWidth, size_t inputHeight, int pitch, ImageFormat inputImageFormat, unsigned char* output, size_t outputWidth, size_t outputHeight, cudaStream_t stream);
    template cudaError_t cudaResizePaddingRGBLike(float* input, size_t inputWidth, size_t inputHeight, int pitch, ImageFormat inputImageFormat, float* output, size_t outputWidth, size_t outputHeight, cudaStream_t stream);
}
