#include <iostream>
#include <fstream>
#include <vector>
#include <queue>
#include <limits>
using namespace std;

void SSSP (char* filename, int source, int target) {
    ifstream file(filename);
    int N, M;
    file >> N >> M;

    vector<vector<pair<int, int>>> graph(N);
    for (int i = 0; i < M; i++) {
        int u, v, w;
        file >> u >> v >> w;
        graph[u].push_back({v, w});
    }

    vector<int> dist(N, numeric_limits<int>::max());
    dist[source] = 0;

    priority_queue<pair<int, int>, vector<pair<int, int>>, greater<pair<int, int>>> pq;
    pq.push({0, source});

    while (!pq.empty()) {
        int u = pq.top().second;
        pq.pop();

        for (auto edge : graph[u]) {
            int v = edge.first;
            int w = edge.second;
            if (dist[v] > dist[u] + w) {
                dist[v] = dist[u] + w;
                pq.push({dist[v], v});
            }
        }
    }

    cout << "Shortest Path from " << source << " to " << target << " is: " << dist[target] << endl;
}

int main(int argc, char* argv[]) {
    SSSP(argv[1], atoi(argv[2]), atoi(argv[3]));
    return 0;
}
