class ErrorReporter {
  constructor(sourceCode) {
    if (typeof sourceCode !== 'string') {
      throw new TypeError('Source code must be a string');
    }
    this.sourceCode = sourceCode;
  }

  reportError(message, lineNumber, columnNumber) {
    if (!message) {
      throw new Error('Message not provided');
    }
    if (typeof message !== 'string') {
      throw new TypeError('Message must be a string');
    }
    if (message.length === 0) {
      throw new Error('Message must not be empty');
    }
    if (!lineNumber) {
      throw new Error('Line number not provided');
    }
    if (typeof lineNumber !== 'number') {
      throw new TypeError('Line number must be a number');
    }
    if (lineNumber < 1) {
      throw new RangeError('Line number is invalid');
    }
    if (lineNumber > this.sourceCode.split('\n').length) {
      throw new RangeError('Line number is out of range');
    }

    if (!columnNumber) {
      throw new Error('Column number not provided');
    }
    if (typeof columnNumber !== 'number') {
      throw new TypeError('Column number must be a number');
    }
    if (columnNumber < 1) {
      throw new RangeError('Column number is invalid');
    }
    if (columnNumber > this.sourceCode.split('\n')[lineNumber - 1].length + 1) {
      throw new RangeError('Column number is out of range');
    }

    const errorLocation = `Error on line ${lineNumber}, column ${columnNumber}: ${message}`;
    const lines = this.sourceCode.split('\n');
    let context = '';
    if (lines.length === 1) {
      context = `1 : ${lines[0]}\n^ : ^`;
    } else if (lineNumber === 1) {
      context = `1 : ${lines[0]}\n^ : ^\n2 : ${lines[1]}`;
    } else if (lineNumber === lines.length) {
      context = `${lineNumber - 1} : ${lines[lineNumber - 2]}\n${lineNumber} : ${lines[lineNumber - 1]}\n^ : ^`;
    } else {
      context = `${lineNumber - 1} : ${lines[lineNumber - 2]}\n${lineNumber} : ${lines[lineNumber - 1]}\n^ : ^\n${lineNumber + 1} : ${lines[lineNumber]}`;
    }

    const contextualError = `${errorLocation}\n\n${context}`;
    console.error(contextualError);
    throw new Error(message);
  }
}
