public class SessionSizeTestServlet extends HttpServlet {
  protected void doGet(HttpServletRequest request, HttpServletResponse response) throws IOException {
    String failParam = request.getParameter("fail");
    String ignoreParam = request.getParameter("ignore");

    HttpSession session = request.getSession();

    if (failParam != null && failParam.equals("true")) {
      try {
        // Add non-serializable objects to the session
        session.setAttribute("nonSerializableObject", new NonSerializableObject());
      } catch (Exception e) {
        response.getWriter().println("Error: " + e.getMessage());
      }
    } else {
      // Add serializable objects to the session
      session.setAttribute("serializableObject", new SerializableObject());
    }

    if (ignoreParam != null && ignoreParam.equals("true")) {
      // Calculate session size, ignoring non-serializable objects
      int sessionSize = calculateSessionSize(session, true);
      response.getWriter().println("Session size (ignoring non-serializable objects): " + sessionSize);
    } else {
      // Calculate session size, including non-serializable objects
      int sessionSize = calculateSessionSize(session, false);
      response.getWriter().println("Session size: " + sessionSize);
    }
  }

  private int calculateSessionSize(HttpSession session, boolean ignoreNonSerializable) {
    Enumeration<String> attributeNames = session.getAttributeNames();
    int size = 0;

    while (attributeNames.hasMoreElements()) {
      String attributeName = attributeNames.nextElement();
      Object attributeValue = session.getAttribute(attributeName);

      if (attributeValue instanceof Serializable || !ignoreNonSerializable) {
        ByteArrayOutputStream baos = new ByteArrayOutputStream();
        try {
          ObjectOutputStream oos = new ObjectOutputStream(baos);
          oos.writeObject(attributeValue);
          oos.close();
          size += baos.size();
        } catch (IOException e) {
          // Handle error when serializing object
          e.printStackTrace();
        }
      }
    }

    return size;
  }

  private class SerializableObject implements Serializable {
    // Define serializable object properties
  }

  private class NonSerializableObject {
    // Define non-serializable object properties
  }
