struct Person {
    String name;
    int id; // Unique ID number for this person
    String email;
    List<PhoneNumber> phoneNumbers;
}

// Define the AddressBook struct
struct AddressBook {
    List<Person> people;
}

// Create a method to add a new person to the address book
void addPerson(AddressBook addressBook, String name, int id, String email, List<PhoneNumber> phoneNumbers) {
    Person newPerson = new Person();
    newPerson.name = name;
    newPerson.id = id;
    newPerson.email = email;
    newPerson.phoneNumbers = phoneNumbers;
    addressBook.people.add(newPerson);
}

// Create a method to update the contact information for a person
void updateContactInformation(AddressBook addressBook, int id, String newEmail, List<PhoneNumber> newPhoneNumbers) {
    for (Person person : addressBook.people) {
        if (person.id == id) {
            person.email = newEmail;
            person.phoneNumbers = newPhoneNumbers;
            break;
        }
    }
}

// Create a method to retrieve the contact information for a person based on their unique ID number
Person getContactInformation(AddressBook addressBook, int id) {
    for (Person person : addressBook.people) {
        if (person.id == id) {
            return person;
        }
    }
    return null;
}
