transformed parameters {
  vector[n] fixed;  // fixed effects response
  vector[n] mu;     // regression mean

  fixed = X*Beta;  // regression fixed effects

  // tack on the random effects
  for(i in 1:n) {
    mu[i] = fixed[i] + gamma[iy[i]] + Eta[i];
  }
}

model {
