  target += poisson_log_lpmf(y | mu);

  // Priors ------------------------------------------------
  // temporal random effects
  gamma ~ normal(0, sigma_y);

  // regression coefficients
  for(i in 1:p) {
    Beta[i] ~ normal(Bm[i], Bs[i]);
  }

  // random effect std devs
